record_types.code:
type ADC_Peripheral is record
   TASKS_START : aliased HAL.UInt32;
   TASKS_STOP  : aliased HAL.UInt32;
   EVENTS_END  : aliased HAL.UInt32;
   INTENSET    : aliased INTENSET_Register;
   INTENCLR    : aliased INTENCLR_Register;
   BUSY        : aliased BUSY_Register;
   ENABLE      : aliased ENABLE_Register;
   CONFIG      : aliased CONFIG_Register;
   RESULT      : aliased RESULT_Register;
   POWER       : aliased POWER_Register;
end record;

type BUSY_Register is record
   BUSY          : BUSY_BUSY_Field;
   Reserved_1_31 : HAL.UInt31;
end record;

type CONFIG_Register is record
   RES            : CONFIG_RES_Field := NRF_SVD.ADC.Val_8BIT;
   INPSEL         : CONFIG_INPSEL_Field :=
                     NRF_SVD.ADC.Supplyonethirdprescaling;
   REFSEL         : CONFIG_REFSEL_Field := NRF_SVD.ADC.Vbg;
   Reserved_7_7   : HAL.Bit := 16#0#;
   PSEL           : CONFIG_PSEL_Field := NRF_SVD.ADC.Disabled;
   EXTREFSEL      : CONFIG_EXTREFSEL_Field := NRF_SVD.ADC.None;
   Reserved_18_31 : HAL.UInt14 := 16#0#;
end record;

type ENABLE_Register is record
   ENABLE        : ENABLE_ENABLE_Field := NRF_SVD.ADC.Disabled;
   Reserved_2_31 : HAL.UInt30 := 16#0#;
end record;

type INTENCLR_Register is record
   END_k         : INTENCLR_END_Field_1 := Intenclr_End_Field_Reset;
   Reserved_1_31 : HAL.UInt31 := 16#0#;
end record;

type INTENSET_Register is record
   END_k         : INTENSET_END_Field_1 := Intenset_End_Field_Reset;
   Reserved_1_31 : HAL.UInt31 := 16#0#;
end record;

type POWER_Register is record
   POWER         : POWER_POWER_Field := NRF_SVD.ADC.Disabled;
   Reserved_1_31 : HAL.UInt31 := 16#0#;
end record;

type RESULT_Register is record
   RESULT         : RESULT_RESULT_Field;
   Reserved_10_31 : HAL.UInt22;
end record;
